queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:format_id ?cg . ?child a :Formats ; p:id ?cg . ?l p:book_id ?pg . ?parent a :Book ; p:id ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Book } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:format_id ?cg . ?child a :Formats ; p:id ?cg . ?l p:book_id ?pg . ?parent a :Book ; p:id ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Book } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?title ?name WHERE {
  ?book_formats a :Book_Formats .
  ?formats a :Formats .
  ?book_formats p:hasFormats ?formats .
  ?books a :Book .
  ?book_formats p:hasBooks ?books .
  ?books p:title ?title .
  ?formats p:name ?name .
} }
}
